/**
 * <p>Inner class to output a time zone name.</p>
 */
private static class TimeZoneNameRule implements Rule {
    private final Locale mLocale;
    private final int mStyle;
    private final TimeZone mTimeZone;

    /**
     * Constructs an instance of {@code TimeZoneNameRule} with the specified properties.
     *
     * @param timeZone the time zone
     * @param locale the locale
     * @param style the style
     */
    TimeZoneNameRule(TimeZone timeZone, Locale locale, int style) {
        mLocale = locale;
        mStyle = style;
        mTimeZone = timeZone;
    }

    /**
     * {@inheritDoc}
     */
    @Override
    public int estimateLength() {
        // We have no access to the Calendar object that will be passed to
        // appendTo so base estimate on the TimeZone passed to the
        // constructor
        return Math.max(
            getTimeZoneDisplay(mTimeZone, false, mStyle, mLocale).length(),
            getTimeZoneDisplay(mTimeZone, true, mStyle, mLocale).length());
    }

    /**
     * {@inheritDoc}
     */
    @Override
    public void appendTo(StringBuffer buffer, Calendar calendar) {
        TimeZone timeZone = calendar.getTimeZone();
        if (timeZone == null) {
            timeZone = mTimeZone;
        }
        // Determine if the time represented by the calendar is in DST
        boolean daylight = calendar.get(Calendar.DST_OFFSET) != 0;
        buffer.append(getTimeZoneDisplay(timeZone, daylight, mStyle, mLocale));
    }
}

